<script setup lang="ts">
import {onMounted,ref} from 'vue';import {api,json} from '../api';import FnButton from '../components/FnButton.vue';import FnCard from '../components/FnCard.vue';import FnPageHeader from '../components/FnPageHeader.vue';import FnTag from '../components/FnTag.vue'
const status=ref<any>(),client=ref<any>(),profiles=ref<any[]>([]),error=ref('');async function refresh(){try{[status.value,client.value,profiles.value]=await Promise.all([api('/api/status'),api('/api/client'),api<any[]>('/api/profiles')]);error.value=''}catch{error.value='无法读取 NetBird 概览。'}}async function toggle(){try{await api(status.value?.connected?'/api/disconnect':'/api/connect',json({}));await refresh()}catch{error.value='连接操作失败。'}}onMounted(refresh)
</script>
<template><FnPageHeader title="概览" description="NetBird 连接与当前 Profile 状态"><template #default><FnButton @click="refresh">刷新</FnButton><FnButton variant="primary" @click="toggle">{{status?.connected?'断开连接':'连接'}}</FnButton></template></FnPageHeader><p v-if="error" class="error">{{error}}</p><div class="stats"><FnCard><small>连接状态</small><h2>{{status?.connected?'已连接':'未连接'}}</h2><FnTag :type="status?.connected?'success':'muted'">{{status?.state||'读取中'}}</FnTag></FnCard><FnCard><small>当前 Profile</small><h2>{{profiles.find(p=>p.active)?.name||'default'}}</h2><p>{{profiles.find(p=>p.active)?.id||'default'}}</p></FnCard><FnCard><small>NetBird 版本</small><h2>{{client?.version||'—'}}</h2><p>{{client?.source||'missing'}} · {{client?.arch||'—'}}</p></FnCard><FnCard><small>Management 状态</small><h2>{{status?.state||'—'}}</h2><p>{{status?.detail||'官方 CLI 状态'}}</p></FnCard></div></template><style scoped>.stats{display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:16px}.stats small,.stats p{color:var(--fn-muted)}.stats h2{margin:12px 0 7px;font-size:23px}.stats p{margin:0;font-size:13px}.error{color:#c43226}</style>
